# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import defaultdict
import numpy as np

app = Flask(__name__)

# In-memory storage for labels
labels = defaultdict(list)

@app.route('/submit_label', methods=['POST'])
def submit_label():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    annotator_id = data['annotator_id']
    
    # Store the label provided by the annotator
    labels[image_id].append((label, annotator_id))
    return jsonify({"message": "Label submitted successfully!"}), 201

@app.route('/aggregate_labels/<image_id>', methods=['GET'])
def aggregate_labels(image_id):
    if image_id not in labels:
        return jsonify({"message": "No labels found for this image."}), 404
    
    label_votes = defaultdict(int)
    for label, _ in labels[image_id]:
        label_votes[label] += 1
    
    # Majority voting
    majority_label = max(label_votes, key=label_votes.get)
    return jsonify({"image_id": image_id, "majority_label": majority_label}), 200

@app.route('/train_model', methods=['POST'])
def train_model():
    # Placeholder for model training logic
    # Example: train_model_on_data(labels)
    return jsonify({"message": "Model trained successfully!"}), 200

if __name__ == '__main__':
    app.run(debug=True)